commits.content:
/* ====== FORMULARIO DE LOGIN ====== */
.login-container {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
  background-color: var(--background-color, #fff);
}

.login-card {
  background: #fff;
  padding: 2.5rem;
  border-radius: 15px;
  box-shadow: 0 4px 20px rgba(0,0,0,0.08);
  width: 100%;
  max-width: 420px;
  text-align: center;
}

.login-card h1 {
  font-size: 1.8rem;
  margin-bottom: 1rem;
  color: var(--accent-color, #f37335);
}

.login-card p {
  margin-bottom: 2rem;
  color: #666;
}

.login-form .form-group {
  text-align: left;
  margin-bottom: 1.2rem;
}

.login-form label {
  display: block;
  font-size: 0.9rem;
  color: #444;
  margin-bottom: 0.3rem;
}

.login-form input {
  width: 100%;
  padding: 0.8rem;
  border: 1px solid #ccc;
  border-radius: 8px;
  font-size: 1rem;
  outline: none;
  transition: all 0.2s ease;
}

.login-form input:focus {
  border-color: var(--accent-color, #f37335);
  box-shadow: 0 0 4px rgba(243,115,53,0.3);
}

.btn-login {
  background-color: var(--accent-color, #f37335);
  color: white;
  border: none;
  width: 100%;
  padding: 0.9rem;
  font-size: 1rem;
  border-radius: 10px;
  cursor: pointer;
  transition: background 0.3s;
}

.btn-login:hover {
  background-color: #e85c1a;
}

.login-links {
  margin-top: 1.2rem;
  font-size: 0.9rem;
  color: #555;
}

.login-links a {
  color: var(--accent-color, #f37335);
  text-decoration: none;
  font-weight: 500;
}

.login-links a:hover {
  text-decoration: underline;
}

.forgot-password {
  display: block;
  margin-bottom: 0.8rem;
}
